import{_ as a,o as t,c as s,j as r,a as n,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"金钟罩","description":"","frontmatter":{},"headers":[],"relativePath":"7.UA/3.功法及改造/金钟罩.md","filePath":"7.UA/3.功法及改造/金钟罩.md"}'),d={name:"7.UA/3.功法及改造/金钟罩.md"};function p(b,e,l,_,i,c){return t(),s("div",null,[...e[0]||(e[0]=[r("h1",{id:"金钟罩",tabindex:"-1"},[n("金钟罩 "),r("a",{class:"header-anchor",href:"#金钟罩","aria-label":'Permalink to "金钟罩"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：新秩序001")])])],-1),o('<h1 id="金钟罩-1" tabindex="-1">金钟罩 <a class="header-anchor" href="#金钟罩-1" aria-label="Permalink to &quot;金钟罩&quot;">​</a></h1><p>这是一门佛门功法，使用者若想学习这门功法必须要对佛学拥有一定的认识和了解才能修行此功法。<br> （具体表现为学习入门内功需要学识下属佛学1，学习核心内功需要佛学3，学习顶级内功需要佛学5）<br> 同时此功法也要求修练者不得故意屠戮无辜，贱淫妇女，偷盗抢掠等行为，<br> （无意中伤到无辜或恶人拿无辜之人当作人质以及可以对恶人拿走他们的东西不算。）（注:主要是由st判断为大概符合我们本世界善恶观的善或恶）<br> 否则功法反噬，失去修练此功法的一切技能，且无法修练佛门功法。</p><p>入门内功:D+600<br> 解锁一个名为内力的能量池，其上限为耐力+力量。回复此能量槽需要诵经冥想修行一小时，可进行一次关键属性的检定，恢复成功数的內力。 也可以在长休后恢复至满。每日以此法恢复上限不能超过总上限三倍。<br> 被动技能<br> 铁布衫:你的筋骨坚实，皮肤受金铁之器刺之犹如皮革一般，全身都能抵抗外力之攻击。获得等于力量上附加成功数的DR/穿刺。</p><p>核心内功:C+1200<br> 被动技能<br> 你的铁布衫升级为获得力量上每点附加成功的DR/—。<br> 金钟罩:你的皮肤犹如铜像般的颜色，而身体也犹如铜像般坚不可摧。你的拳头视为伤害7L的天生武器。<br> 主动技能<br> 金刚劲:以一个自由动作启动，花费三点内力，持续一个场景或15分钟。你可以让金钟罩的内力凝聚在你的肢体上, 使你的肢体皮肤泛起金色的光芒，在使用肉搏挌档时视为具有[格挡值6]特性的天生武器。</p><p>顶级内功:B+2400<br> 被动技能<br> 金刚明王身:你的身体散发出恐怖的力量，身如山岳，立于大地之上,身体皮肤好像佛像一样，散发金色的光芒，犹如金刚明王一般。<br> 获得等于你耐力的天生防御。<br> 金钟罩的效果提升为13L。获得4AP。</p><hr><p>Copyright © 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=a(d,[["render",p]]);export{f as __pageData,m as default};
